package uno.network.ui;

import uno.ai.network.ConnectionAI;
import uno.network.GameServer;
import uno.network.NetworkProtocol;

import java.io.IOException;
import java.util.List;
import java.util.Scanner;

public class HostApp {
    private static final int RULE_COUNT = 8;
    private static final int MIN_PORT = 1024;
    private static final int MAX_PORT = 65535;


    private static final String RESET = ConsoleStyle.RESET;
    private static final String BOLD = ConsoleStyle.BOLD;
    private static final String CYAN = ConsoleStyle.CYAN;
    private static final String GREEN = ConsoleStyle.GREEN;
    private static final String YELLOW = ConsoleStyle.YELLOW;
    private static final String RED = ConsoleStyle.RED;
    private static final String BLUE = ConsoleStyle.BLUE;
    private static final String MAGENTA = ConsoleStyle.MAGENTA;

    private static final String[] RULE_NAMES = {
            "Empilhamento (+2/+4)",
            "Pula e Inverte (Skip 'n Flip)",
            "Sete / Zero",
            "Obrigar jogar carta comprada",
            "Comprar e jogar apos penalidades",
            "Comprar ate combinar",
            "Desafio de blefe +4",
            "Jogar cartas identicas"
    };

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        printWelcome();
        runShell(scanner);
    }

    private static void printWelcome() {
        System.out.println("\n" + BOLD + MAGENTA + "╔════════════════════════════════════╗" + RESET);
        System.out.println(BOLD + MAGENTA +        "║   UNO - Jogo de Cartas em Rede      ║" + RESET);
        System.out.println(BOLD + MAGENTA +        "║         Servidor Host 1.0          ║" + RESET);
        System.out.println(BOLD + MAGENTA +        "╚════════════════════════════════════╝" + RESET + "\n");
    }

    private static void runShell(Scanner scanner) {
        String hostName = System.getProperty("user.name", "Host");
        GameServer server = null;
        boolean hosting = false;
        int currentPort = NetworkProtocol.DEFAULT_GAME_PORT;

        boolean[] rules = new boolean[RULE_COUNT];
        HostShellState state = new HostShellState();

        printMainHelp();

        while (true) {
            String line = prompt(scanner, BOLD + (hosting ? "host> " : "menu> ") + RESET);
            if (line.isEmpty()) continue;

            String[] parts = line.split("\\s+");
            String cmd = parts[0].toLowerCase();

            if (hosting && state.returnToMenu) {
                server.stop();
                server = null;
                hosting = false;
                state.returnToMenu = false;
                System.out.println(CYAN + "Servidor encerrado. Voltando ao menu principal." + RESET);
                printMainHelp();
                continue;
            }

            if (!hosting) {
                switch (cmd) {
                    case "h":
                    case "help":
                        printMainHelp();
                        break;

                    case "host": {
                        Integer parsedPort = null;
                        if (parts.length > 1) {
                            parsedPort = tryParsePort(parts[1]);
                            if (parsedPort == null) {
                                printPortError(parts[1]);
                                break;
                            }
                        }

                        int port = parsedPort != null
                                ? parsedPort
                                : promptForPort(scanner, "Porta", currentPort);

                        state.resetForHosting();
                        server = createAndStartServer(hostName, port, state);
                        if (server == null) {
                            break;
                        }

                        currentPort = server.getPort();
                        hosting = true;
                        printServerOnline(server);
                        printHostHelp();
                        break;
                    }

                    case "q":
                    case "quit":
                    case "exit":
                        System.out.println(CYAN + "Ate mais!" + RESET);
                        return;

                    default:
                        System.out.println(RED + "Comando desconhecido. Digite 'help'." + RESET);
                        break;
                }
                continue;
            }

            switch (cmd) {
                case "h":
                case "help":
                    printHostHelp();
                    break;

                case "host":
                    System.out.println(YELLOW + "Ja hospedando. Use 'stop' antes de hospedar novamente." + RESET);
                    break;

                case "ls":
                case "list":
                    printLobby(server.getSlots());
                    break;

                case "status":
                    printHostStatus(server, currentPort);
                    break;

                case "aihost":
                    if (server.isGameStarted()) {
                        System.out.println(YELLOW + "Nao e possivel conectar o backend de IA durante uma partida." + RESET);
                        break;
                    }
                    handleAiHostConnect(parts, scanner, state);
                    break;

                case "aistatus":
                    printAiStatus(state);
                    break;

                case "aidisconnect":
                    if (server.isGameStarted()) {
                        System.out.println(YELLOW + "Nao e possivel desconectar o backend de IA durante uma partida." + RESET);
                        break;
                    }
                    closeAiConnection(state, "Backend de IA desconectado.");
                    break;

                case "ai":
                case "addai": {
                    if (server.isGameStarted()) {
                        System.out.println(YELLOW + "Nao e possivel alterar o lobby durante uma partida." + RESET);
                        break;
                    }
                    int count = parts.length > 1 ? parseIntOrDefault(parts[1], 1) : 1;
                    state.suppressLobbyPrint = true;
                    try {
                        for (int i = 0; i < Math.max(1, count); i++) {
                            server.addAiBot();
                            System.out.println(GREEN + "  + Bot de IA adicionado" + RESET);
                        }
                    } finally {
                        state.suppressLobbyPrint = false;
                    }
                    printLobby(server.getSlots());
                    break;
                }

                case "rnd":
                case "addrandom": {
                    if (server.isGameStarted()) {
                        System.out.println(YELLOW + "Nao e possivel alterar o lobby durante uma partida." + RESET);
                        break;
                    }
                    int count = parts.length > 1 ? parseIntOrDefault(parts[1], 1) : 1;
                    state.suppressLobbyPrint = true;
                    try {
                        for (int i = 0; i < Math.max(1, count); i++) {
                            server.addRandomBot();
                            System.out.println(GREEN + "  + Bot aleatorio adicionado" + RESET);
                        }
                    } finally {
                        state.suppressLobbyPrint = false;
                    }
                    printLobby(server.getSlots());
                    break;
                }

                case "rm":
                case "remove": {
                    if (server.isGameStarted()) {
                        System.out.println(YELLOW + "Nao e possivel alterar o lobby durante uma partida." + RESET);
                        break;
                    }
                    if (parts.length < 2) {
                        System.out.println(YELLOW + "Uso: remove <nome>" + RESET);
                        continue;
                    }
                    String name = line.substring(line.indexOf(' ') + 1).trim();
                    if (!server.removeSlotByName(name)) {
                        System.out.println(RED + "✗ Nenhum slot encontrado com o nome: " + name + RESET);
                    } else {
                        System.out.println(GREEN + "✓ Jogador removido: " + name + RESET);
                    }
                    break;
                }

                case "rules":
                    printRules(rules);
                    break;

                case "rule":
                    if (server.isGameStarted()) {
                        System.out.println(YELLOW + "Nao e possivel alterar regras durante uma partida." + RESET);
                        break;
                    }
                    if (parts.length < 3) {
                        System.out.println(YELLOW + "Uso: rule <1-8> <on|off>" + RESET);
                        continue;
                    }
                    int idx = parseIntOrDefault(parts[1], -1) - 1;
                    if (idx < 0 || idx >= RULE_COUNT) {
                        System.out.println(RED + "✗ O indice da regra deve ser 1-8." + RESET);
                        continue;
                    }
                    rules[idx] = "on".equalsIgnoreCase(parts[2]) || "true".equalsIgnoreCase(parts[2]);
                    System.out.println(GREEN + "✓ Regra " + (idx + 1) + " definida como: " + (rules[idx] ? "ON" : "OFF") + RESET);
                    printRules(rules);
                    break;

                case "start":
                    if (server.isGameStarted()) {
                        System.out.println(YELLOW + "Uma partida ja esta em andamento." + RESET);
                        continue;
                    }
                    if (server.getAiCount() > 0 && state.aiConnection == null) {
                        System.out.println(RED + "✗ Ha bots de IA no lobby, mas nenhum backend de IA conectado." + RESET);
                        System.out.println(YELLOW + "  Use: aihost <porta>" + RESET);
                        continue;
                    }
                    if (server.getTotalPlayers() < 2) {
                        System.out.println(RED + "✗ Sao necessarios pelo menos 2 jogadores para iniciar." + RESET);
                        continue;
                    }
                    System.out.println(GREEN + BOLD + " Iniciando partida..." + RESET);
                    if (!server.startGame(state.aiConnection, rules, "game-" + System.currentTimeMillis(), -1)) {
                        System.out.println(RED + "✗ Nao foi possivel iniciar a partida. Verifique o lobby e o estado do servidor." + RESET);
                    }
                    break;

                case "stopmatch":
                    if (!server.isGameStarted()) {
                        System.out.println(YELLOW + "Nao ha partida ativa para parar." + RESET);
                        break;
                    }
                    if (server.stopCurrentMatch(NetworkProtocol.R_MATCH_STOPPED_BY_HOST)) {
                        System.out.println(CYAN + "Partida atual encerrada. O servidor permanece online." + RESET);
                    } else {
                        System.out.println(RED + "✗ Nao foi possivel encerrar a partida atual." + RESET);
                    }
                    break;

                case "stop":
                    closeAiConnection(state, null);
                    server.stop();
                    server = null;
                    hosting = false;
                    System.out.println(CYAN + "Servidor encerrado. Digite 'host' para hospedar novamente." + RESET);
                    printMainHelp();
                    break;

                case "clear":
                    for (int i = 0; i < 30; i++) System.out.println();
                    break;

                case "q":
                case "quit":

                case "exit":
                    closeAiConnection(state, null);
                    server.stop();
                    System.out.println(CYAN + "Servidor encerrado. Ate mais!" + RESET);
                    return;

                case "menu":
                    closeAiConnection(state, null);
                    server.stop();
                    server = null;
                    hosting = false;
                    System.out.println(CYAN + "Servidor encerrado. Voltando ao menu principal." + RESET);
                    printMainHelp();
                    break;

                default:
                    System.out.println(RED + "Comando desconhecido. Digite 'help'." + RESET);
                    break;
            }
        }
    }

    private static GameServer createAndStartServer(String hostName, int port, HostShellState state) {
        GameServer server = new GameServer(hostName);
        server.setOnLobbyChanged(slots -> {
            if (!state.suppressLobbyPrint) {
                printLobby(slots);
            }
        });

        server.setOnMatchEnded(() -> {
            System.out.println(GREEN + BOLD + "✓ Partida encerrada. Voce pode iniciar outra." + RESET);
            printHostHelp();
        });

        server.setOnPlayerDisconnected(playerName -> {
            System.out.println(RED + BOLD + "✗ Jogador '" + playerName + "' desconectou durante a partida. Voltando ao menu." + RESET);
            state.returnToMenu = true;
        });

        try {
            server.start(port);
        } catch (IOException e) {
            System.err.println(RED + "✗ Nao foi possivel iniciar o servidor: " + e.getMessage() + RESET);
            return null;
        }

        return server;
    }

    private static void printMainHelp() {
        System.out.println(BOLD + CYAN + "\n═══ Comandos Principais do Host ═══" + RESET);
        System.out.println(GREEN + "  help | h" + RESET + "                         Mostrar comandos");
        System.out.println(GREEN + "  host [porta]" + RESET + "                      Iniciar hospedagem (pede porta se omitida)");
        System.out.println(GREEN + "  quit | q" + RESET + "                         Sair do host");
        System.out.println();
    }

    private static void printHostHelp() {
        System.out.println(BOLD + CYAN + "\n═══ Comandos do Servidor Host ═══" + RESET);
        System.out.println(GREEN + "  help | h" + RESET + "                            Mostrar comandos");
        System.out.println(GREEN + "  status" + RESET + "                              Mostrar status do servidor/partida");
        System.out.println(GREEN + "  list | ls" + RESET + "                           Listar slots do lobby");
        System.out.println(GREEN + "  addai [n] | ai [n]" + RESET + "                  Adicionar bot(s) de IA");
        System.out.println(GREEN + "  addrandom [n] | rnd [n]" + RESET + "             Adicionar bot(s) aleatorios");
        System.out.println(GREEN + "  remove <name> | rm <name>" + RESET + "           Remover/expulsar jogador");
        System.out.println(GREEN + "  rules" + RESET + "                               Mostrar todas as regras");
        System.out.println(GREEN + "  rule <1-8> <on|off>" + RESET + "                 Alternar uma regra");
        System.out.println(GREEN + "  aihost [porta]" + RESET + "                       Aguardar conexao do backend de IA");
        System.out.println(GREEN + "  aistatus" + RESET + "                            Mostrar status do backend de IA");
        System.out.println(GREEN + "  aidisconnect" + RESET + "                        Desconectar backend de IA");
        System.out.println(GREEN + "  start" + RESET + "                               Iniciar partida");
        System.out.println(GREEN + "  stopmatch" + RESET + "                           Encerrar apenas a partida atual");
        System.out.println(GREEN + "  stop" + RESET + "                                Parar hospedagem e voltar ao menu principal");
        System.out.println(GREEN + "  clear" + RESET + "                               Limpar tela");
        System.out.println(GREEN + "  quit | q" + RESET + "                            Encerrar servidor e sair");
        System.out.println();
    }

    private static void printHostStatus(GameServer server, int fallbackPort) {
        String running = server.isRunning() ? GREEN + "ONLINE" + RESET : RED + "OFFLINE" + RESET;
        String match = server.isGameStarted() ? YELLOW + "EM ANDAMENTO" + RESET : GREEN + "OCIOSO" + RESET;
        int activePort = server.isRunning() ? server.getPort() : fallbackPort;
        System.out.println(CYAN + "Servidor: " + running + ", partida: " + match + ", porta: " + activePort + RESET);
        System.out.println(CYAN + "Lobby humanos/total: " + server.getHumanCount() + "/" + server.getTotalPlayers() + RESET);
    }


    private static void handleAiHostConnect(String[] parts, Scanner scanner, HostShellState state) {
        if (state.aiConnection != null) {
            System.out.println(YELLOW + "O backend de IA ja esta conectado na porta " + state.aiPort + "." + RESET);
            return;
        }

        int port;
        if (parts.length > 1) {
            Integer parsed = tryParsePort(parts[1]);
            if (parsed == null) {
                printPortError(parts[1]);
                return;
            }
            port = parsed;
        } else {
            port = promptForPort(scanner, "Porta do backend de IA", NetworkProtocol.DEFAULT_GAME_PORT + 1000);
        }

        ConnectionAI connectionAI = new ConnectionAI();
        System.out.println(CYAN + "Aguardando backend de IA na porta " + port + "..." + RESET);
        try {
            connectionAI.connect(port, false);
            state.aiConnection = connectionAI;
            state.aiPort = port;
            System.out.println(GREEN + "✓ Backend de IA conectado na porta " + port + RESET);
        } catch (IOException e) {
            System.out.println(RED + "✗ Nao foi possivel conectar o backend de IA: " + e.getMessage() + RESET);
        }
    }

    private static void printAiStatus(HostShellState state) {
        if (state.aiConnection == null) {
            System.out.println(YELLOW + "Backend de IA: desconectado" + RESET);
        } else {
            System.out.println(GREEN + "Backend de IA: conectado na porta " + state.aiPort + RESET);
        }
    }

    private static void closeAiConnection(HostShellState state, String successMessage) {
        if (state.aiConnection == null) {
            return;
        }

        try {
            state.aiConnection.close();
        } catch (Exception ignored) {
            // Ignore shutdown failures to keep host flow resilient.
        }

        state.aiConnection = null;
        state.aiPort = -1;

        if (successMessage != null && !successMessage.isEmpty()) {
            System.out.println(CYAN + successMessage + RESET);
        }
    }

    private static void printServerOnline(GameServer server) {
        System.out.println(GREEN + BOLD + "✓ Servidor online em:" + RESET);
        for (String desc : server.getLocalAddressDescriptions()) {
            int split = desc.lastIndexOf(" (");
            String ip = split > 0 ? desc.substring(0, split) : desc;
            String adapter = split > 0 && desc.endsWith(")")
                    ? desc.substring(split + 2, desc.length() - 1)
                    : "Adaptador desconhecido";

            System.out.println(CYAN + "  " + ip + ":" + server.getPort() + RESET);
            System.out.println(CYAN + "    adaptador: " + adapter + RESET);
        }
    }

    private static void printLobby(List<GameServer.LobbySlot> slots) {
        System.out.println(BOLD + CYAN + "Lobby (" + slots.size() + " jogadores):" + RESET);
        if (slots.isEmpty()) {
            System.out.println(YELLOW + "  (vazio)" + RESET);
            return;
        }
        for (GameServer.LobbySlot slot : slots) {
            String typeColor = "AI".equals(slot.type.toString()) ? BLUE :
                             "RANDOM".equals(slot.type.toString()) ? MAGENTA : GREEN;
            System.out.println("  - " + GREEN + slot.name + RESET + " [" + typeColor + slot.type + RESET + "]");
        }
    }

    private static void printRules(boolean[] rules) {
        System.out.println(BOLD + CYAN + "Configuracao de Regras:" + RESET);

        for (int i = 0; i < RULE_COUNT; i++) {
            String status = rules[i] ? GREEN + "ON" + RESET : RED + "OFF" + RESET;
            System.out.println("  " + CYAN + (i + 1) + RESET + ") " + RULE_NAMES[i] + " = " + status);
        }
    }

    private static String prompt(Scanner scanner, String text) {
        System.out.print(text);
        return scanner.nextLine().trim();
    }

    private static int parseIntOrDefault(String raw, int fallback) {
        try {
            return Integer.parseInt(raw.trim());
        } catch (Exception ignored) {
            return fallback;
        }
    }

    private static int promptForPort(Scanner scanner, String label, int fallback) {
        while (true) {
            String raw = prompt(scanner, label + " [" + fallback + "]: ");
            if (raw.isEmpty()) return fallback;
            Integer parsed = tryParsePort(raw);
            if (parsed != null) return parsed;
            printPortError(raw);
        }
    }

    private static Integer tryParsePort(String raw) {
        int value;

        try {
            value = Integer.parseInt(raw.trim());
        } catch (Exception ignored) {
            return null;
        }

        if (value < MIN_PORT || value > MAX_PORT) return null;

        return value;
    }

    private static void printPortError(String raw) {
        System.out.println(RED + "✗ Porta invalida: '" + raw + "'. Digite um numero no intervalo " + MIN_PORT + "-" + MAX_PORT + "." + RESET);
    }

    private static final class HostShellState {
        private boolean suppressLobbyPrint;
        private boolean returnToMenu;
        private ConnectionAI aiConnection;
        private int aiPort = -1;

        private void resetForHosting() {
            suppressLobbyPrint = false;
            returnToMenu = false;
        }
    }
}

package uno.network.ui;

import uno.ai.network.ConnectionAI;
import uno.network.GameServer;
import uno.network.NetworkProtocol;

import java.io.IOException;
import java.util.List;
import java.util.Scanner;

public class HostApp {
    private static final int RULE_COUNT = 8;
    private static final int MIN_PORT = 1024;
    private static final int MAX_PORT = 65535;


    private static final String RESET = ConsoleStyle.RESET;
    private static final String BOLD = ConsoleStyle.BOLD;
    private static final String CYAN = ConsoleStyle.CYAN;
    private static final String GREEN = ConsoleStyle.GREEN;
    private static final String YELLOW = ConsoleStyle.YELLOW;
    private static final String RED = ConsoleStyle.RED;
    private static final String BLUE = ConsoleStyle.BLUE;
    private static final String MAGENTA = ConsoleStyle.MAGENTA;

    private static final String[] RULE_NAMES = {
            "Empilhamento (+2/+4)",
            "Pula e Inverte (Skip 'n Flip)",
            "Sete / Zero",
            "Obrigar jogar carta comprada",
            "Comprar e jogar apos penalidades",
            "Comprar ate combinar",
            "Desafio de blefe +4",
            "Jogar cartas identicas"
    };

    private static final boolean[] RULE_PRESET_OFFICIAL = {
            false, false, false, false, false, false, true, false
    };

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        printWelcome();
        runShell(scanner);
    }

    private static void printWelcome() {
        System.out.println("\n" + BOLD + MAGENTA + "╔════════════════════════════════════╗" + RESET);
        System.out.println(BOLD + MAGENTA +        "║   UNO - Jogo de Cartas em Rede      ║" + RESET);
        System.out.println(BOLD + MAGENTA +        "║         Servidor Host 1.0          ║" + RESET);
        System.out.println(BOLD + MAGENTA +        "╚════════════════════════════════════╝" + RESET + "\n");
    }

    private static void runShell(Scanner scanner) {
        String hostName = System.getProperty("user.name", "Host");
        GameServer server = null;
        boolean hosting = false;
        int currentPort = NetworkProtocol.DEFAULT_GAME_PORT;

        boolean[] rules = new boolean[RULE_COUNT];
        HostShellState state = new HostShellState();

        printMainHelp();

        while (true) {
            String line = prompt(scanner, BOLD + (hosting ? "host> " : "menu> ") + RESET);
            if (line.isEmpty()) continue;

            String[] parts = line.split("\\s+");
            String cmd = parts[0].toLowerCase();

            if (hosting && state.returnToMenu) {
                server.stop();
                server = null;
                hosting = false;
                state.returnToMenu = false;
                System.out.println(CYAN + "Servidor encerrado. Voltando ao menu principal." + RESET);
                printMainHelp();
                continue;
            }

            if (!hosting) {
                switch (cmd) {
                    case "h":
                    case "help":
                        printMainHelp();
                        break;

                    case "host": {
                        Integer parsedPort = null;
                        if (parts.length > 1) {
                            parsedPort = tryParsePort(parts[1]);
                            if (parsedPort == null) {
                                printPortError(parts[1]);
                                break;
                            }
                        }

                        int port = parsedPort != null
                                ? parsedPort
                                : promptForPort(scanner, "Porta", currentPort);

                        state.resetForHosting();
                        server = createAndStartServer(hostName, port, state);
                        if (server == null) {
                            break;
                        }

                        currentPort = server.getPort();
                        hosting = true;
                        printServerOnline(server);
                        printHostHelp();
                        break;
                    }

                    case "q":
                    case "quit":
                    case "exit":
                        System.out.println(CYAN + "Ate mais!" + RESET);
                        return;

                    default:
                        System.out.println(RED + "Comando desconhecido. Digite 'help'." + RESET);
                        break;
                }
                continue;
            }

            switch (cmd) {
                case "h":
                case "help":
                    printHostHelp();
                    break;

                case "host":
                    System.out.println(YELLOW + "Ja hospedando. Use 'stop' antes de hospedar novamente." + RESET);
                    break;

                case "ls":
                case "list":
                    printLobby(server.getSlots());
                    break;

                case "status":
                    printHostStatus(server, currentPort);
                    break;

                case "aihost":
                    if (server.isGameStarted()) {
                        System.out.println(YELLOW + "Nao e possivel conectar o backend de IA durante uma partida." + RESET);
                        break;
                    }
                    handleAiHostConnect(parts, scanner, state);
                    break;

                case "aistatus":
                    printAiStatus(state);
                    break;

                case "aidisconnect":
                    if (server.isGameStarted()) {
                        System.out.println(YELLOW + "Nao e possivel desconectar o backend de IA durante uma partida." + RESET);
                        break;
                    }
                    closeAiConnection(state, "Backend de IA desconectado.");
                    break;

                case "ai":
                case "addai": {
                    if (server.isGameStarted()) {
                        System.out.println(YELLOW + "Nao e possivel alterar o lobby durante uma partida." + RESET);
                        break;
                    }
                    int count = parts.length > 1 ? parseIntOrDefault(parts[1], 1) : 1;
                    state.suppressLobbyPrint = true;
                    try {
                        for (int i = 0; i < Math.max(1, count); i++) {
                            server.addAiBot();
                            System.out.println(GREEN + "  + Bot de IA adicionado" + RESET);
                        }
                    } finally {
                        state.suppressLobbyPrint = false;
                    }
                    printLobby(server.getSlots());
                    break;
                }

                case "rnd":
                case "addrandom": {
                    if (server.isGameStarted()) {
                        System.out.println(YELLOW + "Nao e possivel alterar o lobby durante uma partida." + RESET);
                        break;
                    }
                    int count = parts.length > 1 ? parseIntOrDefault(parts[1], 1) : 1;
                    state.suppressLobbyPrint = true;
                    try {
                        for (int i = 0; i < Math.max(1, count); i++) {
                            server.addRandomBot();
                            System.out.println(GREEN + "  + Bot aleatorio adicionado" + RESET);
                        }
                    } finally {
                        state.suppressLobbyPrint = false;
                    }
                    printLobby(server.getSlots());
                    break;
                }

                case "rm":
                case "remove": {
                    if (server.isGameStarted()) {
                        System.out.println(YELLOW + "Nao e possivel alterar o lobby durante uma partida." + RESET);
                        break;
                    }
                    if (parts.length < 2) {
                        System.out.println(YELLOW + "Uso: remove <nome>" + RESET);
                        continue;
                    }
                    String name = line.substring(line.indexOf(' ') + 1).trim();
                    if (!server.removeSlotByName(name)) {
                        System.out.println(RED + "✗ Nenhum slot encontrado com o nome: " + name + RESET);
                    } else {
                        System.out.println(GREEN + "✓ Jogador removido: " + name + RESET);
                    }
                    break;
                }

                case "rules":
                    printRules(rules);
                    break;

                case "rule":
                    if (server.isGameStarted()) {
                        System.out.println(YELLOW + "Nao e possivel alterar regras durante uma partida." + RESET);
                        break;
                    }
                    if (parts.length < 3) {
                        System.out.println(YELLOW + "Uso: rule <1-8> <on|off>" + RESET);
                        continue;
                    }
                    int idx = parseIntOrDefault(parts[1], -1) - 1;
                    if (idx < 0 || idx >= RULE_COUNT) {
                        System.out.println(RED + "✗ O indice da regra deve ser 1-8." + RESET);
                        continue;
                    }
                    rules[idx] = "on".equalsIgnoreCase(parts[2]) || "true".equalsIgnoreCase(parts[2]);
                    System.out.println(GREEN + "✓ Regra " + (idx + 1) + " definida como: " + (rules[idx] ? "ON" : "OFF") + RESET);
                    printRules(rules);
                    break;

                case "preset":
                    if (server.isGameStarted()) {
                        System.out.println(YELLOW + "Nao e possivel alterar regras durante uma partida." + RESET);
                        break;
                    }
                    if (parts.length < 2) {
                        System.out.println(YELLOW + "Uso: preset <official>" + RESET);
                        continue;
                    }
                    if ("official".equalsIgnoreCase(parts[1])) {
                        System.arraycopy(RULE_PRESET_OFFICIAL, 0, rules, 0, RULE_COUNT);
                        System.out.println(GREEN + "✓ Preset aplicado: OFFICIAL" + RESET);
                        printRules(rules);
                    } else {
                        System.out.println(RED + "✗ Preset desconhecido. Disponivel: official" + RESET);
                    }
                    break;

                case "start":
                    if (server.isGameStarted()) {
                        System.out.println(YELLOW + "Uma partida ja esta em andamento." + RESET);
                        continue;
                    }
                    if (server.getAiCount() > 0 && state.aiConnection == null) {
                        System.out.println(RED + "✗ Ha bots de IA no lobby, mas nenhum backend de IA conectado." + RESET);
                        System.out.println(YELLOW + "  Use: aihost <porta>" + RESET);
                        continue;
                    }
                    if (server.getTotalPlayers() < 2) {
                        System.out.println(RED + "✗ Sao necessarios pelo menos 2 jogadores para iniciar." + RESET);
                        continue;
                    }
                    System.out.println(GREEN + BOLD + " Iniciando partida..." + RESET);
                    if (!server.startGame(state.aiConnection, rules, "game-" + System.currentTimeMillis(), -1)) {
                        System.out.println(RED + "✗ Nao foi possivel iniciar a partida. Verifique o lobby e o estado do servidor." + RESET);
                    }
                    break;

                case "stopmatch":
                    if (!server.isGameStarted()) {
                        System.out.println(YELLOW + "Nao ha partida ativa para parar." + RESET);
                        break;
                    }
                    if (server.stopCurrentMatch(NetworkProtocol.R_MATCH_STOPPED_BY_HOST)) {
                        System.out.println(CYAN + "Partida atual encerrada. O servidor permanece online." + RESET);
                    } else {
                        System.out.println(RED + "✗ Nao foi possivel encerrar a partida atual." + RESET);
                    }
                    break;

                case "stop":
                    closeAiConnection(state, null);
                    server.stop();
                    server = null;
                    hosting = false;
                    System.out.println(CYAN + "Servidor encerrado. Digite 'host' para hospedar novamente." + RESET);
                    printMainHelp();
                    break;

                case "clear":
                    for (int i = 0; i < 30; i++) System.out.println();
                    break;

                case "q":
                case "quit":

                case "exit":
                    closeAiConnection(state, null);
                    server.stop();
                    System.out.println(CYAN + "Servidor encerrado. Ate mais!" + RESET);
                    return;

                case "menu":
                    closeAiConnection(state, null);
                    server.stop();
                    server = null;
                    hosting = false;
                    System.out.println(CYAN + "Servidor encerrado. Voltando ao menu principal." + RESET);
                    printMainHelp();
                    break;

                default:
                    System.out.println(RED + "Comando desconhecido. Digite 'help'." + RESET);
                    break;
            }
        }
    }

    private static GameServer createAndStartServer(String hostName, int port, HostShellState state) {
        GameServer server = new GameServer(hostName);
        server.setOnLobbyChanged(slots -> {
            if (!state.suppressLobbyPrint) {
                printLobby(slots);
            }
        });

        server.setOnMatchEnded(() -> {
            System.out.println(GREEN + BOLD + "✓ Partida encerrada. Voce pode iniciar outra." + RESET);
            printHostHelp();
        });

        server.setOnPlayerDisconnected(playerName -> {
            System.out.println(RED + BOLD + "✗ Jogador '" + playerName + "' desconectou durante a partida. Voltando ao menu." + RESET);
            state.returnToMenu = true;
        });

        try {
            server.start(port);
        } catch (IOException e) {
            System.err.println(RED + "✗ Nao foi possivel iniciar o servidor: " + e.getMessage() + RESET);
            return null;
        }

        return server;
    }

    private static void printMainHelp() {
        System.out.println(BOLD + CYAN + "\n═══ Comandos Principais do Host ═══" + RESET);
        System.out.println(GREEN + "  help | h" + RESET + "                         Mostrar comandos");
        System.out.println(GREEN + "  host [porta]" + RESET + "                      Iniciar hospedagem (pede porta se omitida)");
        System.out.println(GREEN + "  quit | q" + RESET + "                         Sair do host");
        System.out.println();
    }

    private static void printHostHelp() {
        System.out.println(BOLD + CYAN + "\n═══ Comandos do Servidor Host ═══" + RESET);
        System.out.println(GREEN + "  help | h" + RESET + "                            Mostrar comandos");
        System.out.println(GREEN + "  status" + RESET + "                              Mostrar status do servidor/partida");
        System.out.println(GREEN + "  list | ls" + RESET + "                           Listar slots do lobby");
        System.out.println(GREEN + "  addai [n] | ai [n]" + RESET + "                  Adicionar bot(s) de IA");
        System.out.println(GREEN + "  addrandom [n] | rnd [n]" + RESET + "             Adicionar bot(s) aleatorios");
        System.out.println(GREEN + "  remove <name> | rm <name>" + RESET + "           Remover/expulsar jogador");
        System.out.println(GREEN + "  rules" + RESET + "                               Mostrar todas as regras");
        System.out.println(GREEN + "  rule <1-8> <on|off>" + RESET + "                 Alternar uma regra");
        System.out.println(GREEN + "  preset <official>" + RESET + "                 Aplicar preset de regras");
        System.out.println(GREEN + "  aihost [porta]" + RESET + "                       Aguardar conexao do backend de IA");
        System.out.println(GREEN + "  aistatus" + RESET + "                            Mostrar status do backend de IA");
        System.out.println(GREEN + "  aidisconnect" + RESET + "                        Desconectar backend de IA");
        System.out.println(GREEN + "  start" + RESET + "                               Iniciar partida");
        System.out.println(GREEN + "  stopmatch" + RESET + "                           Encerrar apenas a partida atual");
        System.out.println(GREEN + "  stop" + RESET + "                                Parar hospedagem e voltar ao menu principal");
        System.out.println(GREEN + "  clear" + RESET + "                               Limpar tela");
        System.out.println(GREEN + "  quit | q" + RESET + "                            Encerrar servidor e sair");
        System.out.println();
    }

    private static void printHostStatus(GameServer server, int fallbackPort) {
        String running = server.isRunning() ? GREEN + "ONLINE" + RESET : RED + "OFFLINE" + RESET;
        String match = server.isGameStarted() ? YELLOW + "EM ANDAMENTO" + RESET : GREEN + "OCIOSO" + RESET;
        int activePort = server.isRunning() ? server.getPort() : fallbackPort;
        System.out.println(CYAN + "Servidor: " + running + ", partida: " + match + ", porta: " + activePort + RESET);
        System.out.println(CYAN + "Lobby humanos/total: " + server.getHumanCount() + "/" + server.getTotalPlayers() + RESET);
    }


    private static void handleAiHostConnect(String[] parts, Scanner scanner, HostShellState state) {
        if (state.aiConnection != null) {
            System.out.println(YELLOW + "O backend de IA ja esta conectado na porta " + state.aiPort + "." + RESET);
            return;
        }

        int port;
        if (parts.length > 1) {
            Integer parsed = tryParsePort(parts[1]);
            if (parsed == null) {
                printPortError(parts[1]);
                return;
            }
            port = parsed;
        } else {
            port = promptForPort(scanner, "Porta do backend de IA", NetworkProtocol.DEFAULT_GAME_PORT + 1000);
        }

        ConnectionAI connectionAI = new ConnectionAI();
        System.out.println(CYAN + "Aguardando backend de IA na porta " + port + "..." + RESET);
        try {
            connectionAI.connect(port, false);
            state.aiConnection = connectionAI;
            state.aiPort = port;
            System.out.println(GREEN + "✓ Backend de IA conectado na porta " + port + RESET);
        } catch (IOException e) {
            System.out.println(RED + "✗ Nao foi possivel conectar o backend de IA: " + e.getMessage() + RESET);
        }
    }

    private static void printAiStatus(HostShellState state) {
        if (state.aiConnection == null) {
            System.out.println(YELLOW + "Backend de IA: desconectado" + RESET);
        } else {
            System.out.println(GREEN + "Backend de IA: conectado na porta " + state.aiPort + RESET);
        }
    }

    private static void closeAiConnection(HostShellState state, String successMessage) {
        if (state.aiConnection == null) {
            return;
        }

        try {
            state.aiConnection.close();
        } catch (Exception ignored) {
            // Ignore shutdown failures to keep host flow resilient.
        }

        state.aiConnection = null;
        state.aiPort = -1;

        if (successMessage != null && !successMessage.isEmpty()) {
            System.out.println(CYAN + successMessage + RESET);
        }
    }

    private static void printServerOnline(GameServer server) {
        System.out.println(GREEN + BOLD + "✓ Servidor online em:" + RESET);
        for (String desc : server.getLocalAddressDescriptions()) {
            int split = desc.lastIndexOf(" (");
            String ip = split > 0 ? desc.substring(0, split) : desc;
            String adapter = split > 0 && desc.endsWith(")")
                    ? desc.substring(split + 2, desc.length() - 1)
                    : "Adaptador desconhecido";

            System.out.println(CYAN + "  " + ip + ":" + server.getPort() + RESET);
            System.out.println(CYAN + "    adaptador: " + adapter + RESET);
        }
    }

    private static void printLobby(List<GameServer.LobbySlot> slots) {
        System.out.println(BOLD + CYAN + "Lobby (" + slots.size() + " jogadores):" + RESET);
        if (slots.isEmpty()) {
            System.out.println(YELLOW + "  (vazio)" + RESET);
            return;
        }
        for (GameServer.LobbySlot slot : slots) {
            String typeColor = "AI".equals(slot.type.toString()) ? BLUE :
                             "RANDOM".equals(slot.type.toString()) ? MAGENTA : GREEN;
            System.out.println("  - " + GREEN + slot.name + RESET + " [" + typeColor + slot.type + RESET + "]");
        }
    }

    private static void printRules(boolean[] rules) {
        System.out.println(BOLD + CYAN + "Configuracao de Regras:" + RESET);

        for (int i = 0; i < RULE_COUNT; i++) {
            String status = rules[i] ? GREEN + "ON" + RESET : RED + "OFF" + RESET;
            System.out.println("  " + CYAN + (i + 1) + RESET + ") " + RULE_NAMES[i] + " = " + status);
        }
    }

    private static String prompt(Scanner scanner, String text) {
        System.out.print(text);
        return scanner.nextLine().trim();
    }

    private static int parseIntOrDefault(String raw, int fallback) {
        try {
            return Integer.parseInt(raw.trim());
        } catch (Exception ignored) {
            return fallback;
        }
    }

    private static int promptForPort(Scanner scanner, String label, int fallback) {
        while (true) {
            String raw = prompt(scanner, label + " [" + fallback + "]: ");
            if (raw.isEmpty()) return fallback;
            Integer parsed = tryParsePort(raw);
            if (parsed != null) return parsed;
            printPortError(raw);
        }
    }

    private static Integer tryParsePort(String raw) {
        int value;

        try {
            value = Integer.parseInt(raw.trim());
        } catch (Exception ignored) {
            return null;
        }

        if (value < MIN_PORT || value > MAX_PORT) return null;

        return value;
    }

    private static void printPortError(String raw) {
        System.out.println(RED + "✗ Porta invalida: '" + raw + "'. Digite um numero no intervalo " + MIN_PORT + "-" + MAX_PORT + "." + RESET);
    }

    private static final class HostShellState {
        private boolean suppressLobbyPrint;
        private boolean returnToMenu;
        private ConnectionAI aiConnection;
        private int aiPort = -1;

        private void resetForHosting() {
            suppressLobbyPrint = false;
            returnToMenu = false;
        }
    }
}

package uno.ai.training;

import uno.ai.network.ConnectionAI;
import uno.game.engine.Simulation;

import java.io.IOException;
import java.util.List;
import java.util.Random;

public class Training {

    private static final String DEFAULT_CONFIG = "res/training_official_4p_100.properties";

    public static void main(String[] args) {
        String configPath = args.length > 0 ? args[0] : DEFAULT_CONFIG;

        TrainingConfig config;
        try {
            config = TrainingConfig.load(configPath);
        } catch (IOException e) {
            System.err.println("Failed to load config from '" + configPath + "': " + e.getMessage());
            System.exit(1);
            return;
        }

        System.out.println("Loaded config: " + config);
        System.out.println("From: " + configPath);

        for (int i = 0; i < config.numClients; i++) {
            int port = config.startPort + i;
            String id = String.valueOf(i + 1);
            new Thread(() -> runRoutine(port, id, config), "trainer-" + id).start();
        }
    }

    private static void runRoutine(int port, String id, TrainingConfig config) {
        ConnectionAI ConnectionAI = new ConnectionAI();

        try {
            ConnectionAI.connect(port);
        } catch (IOException e) {
            throw new RuntimeException("Thread " + id + " could not connect on port " + port, e);
        }

        List<TrainingPhase> phases = config.phases;
        int loopStart = config.loopStartPhase - 1;

        for (int i = 0; i < loopStart; i++) {
            runPhase(phases.get(i), id, ConnectionAI);
        }

        if (config.loopInfinite) {
            while (true) {
                try {
                    for (int i = loopStart; i < phases.size(); i++) {
                        runPhase(phases.get(i), id, ConnectionAI);
                    }
                } catch (Exception e) {
                    System.err.println(id + ". Unhandled exception in training loop.");
                    throw new RuntimeException(e);
                }
            }
        } else {
            for (int i = loopStart; i < phases.size(); i++) {
                runPhase(phases.get(i), id, ConnectionAI);
            }
        }
    }

    private static void runPhase(TrainingPhase phase, String id, ConnectionAI ConnectionAI) {
        switch (phase.type) {
            case FIXED: runFixedPhase (phase, id, ConnectionAI); break;
            case RANDOM_AI: runRandomAIPhase (phase, id, ConnectionAI); break;
            case MIXED: runMixedPhase (phase, id, ConnectionAI); break;
            case EXHAUSTIVE: runExhaustivePhase(phase, id, ConnectionAI); break;
        }
    }

    private static void runFixedPhase(TrainingPhase phase, String id, ConnectionAI ConnectionAI) {
        Random rng = new Random();
        System.out.println(id + ". [FIXED] " + phase.games + " games - " + phase.aiPlayers + " AI, " + phase.randomPlayers + " random players.");
        displayRules(phase);

        for (int i = 0; i < phase.games; i++) {
            runGame(phase.aiPlayers, phase.randomPlayers, phase.resolveRules(rng), id, ConnectionAI);
        }
    }

    private static void runRandomAIPhase(TrainingPhase phase, String id, ConnectionAI ConnectionAI) {
        Random rng = new Random();
        int range = phase.aiPlayersMax - phase.aiPlayersMin + 1;
        System.out.println(id + ". [RANDOM_AI] " + phase.games + " games - minimum of " + phase.aiPlayersMin + " AI players and maximum of " + phase.aiPlayersMax + " AI players.");
        displayRules(phase);

        for (int i = 0; i < phase.games; i++) {
            int aiPlayers = rng.nextInt(range) + phase.aiPlayersMin;
            runGame(aiPlayers, 0, phase.resolveRules(rng), id, ConnectionAI);
        }
    }

    private static void runMixedPhase(TrainingPhase phase, String id, ConnectionAI ConnectionAI) {
        Random rng = new Random();
        int range = phase.aiPlayersMax - phase.aiPlayersMin + 1;
        System.out.println(id + ". [MIXED] " + phase.games + " games - minimum of " + phase.aiPlayersMin + " AI players and maximum of " + phase.aiPlayersMax + " AI players.");
        displayRules(phase);

        for (int i = 0; i < phase.games; i++) {
            int aiPlayers = rng.nextInt(range) + phase.aiPlayersMin;
            int maxRandom = 10 - aiPlayers;
            int randomPlayers = maxRandom == 0 ? 1 : rng.nextInt(maxRandom) + 1;
            runGame(aiPlayers, randomPlayers, phase.resolveRules(rng), id, ConnectionAI);
        }
    }

    private static void runExhaustivePhase(TrainingPhase phase, String id, ConnectionAI ConnectionAI) {
        Random rng = new Random();
        System.out.println(id + ". [EXHAUSTIVE] " + phase.iterations + " iterations.");
        displayRules(phase);

        for (int k = 0; k < phase.iterations; k++) {
            for (int total = 2; total <= 10; total++) {
                for (int ai = 1; ai < total; ai++) {
                    runGame(ai, total - ai, phase.resolveRules(rng), id, ConnectionAI);
                }
                System.out.println(id + ". All possible games with " + total + " players done.");
            }
        }
    }

    private static void runGame(int aiPlayers, int randomPlayers, boolean[] rules, String id, ConnectionAI ConnectionAI) {
        Simulation simulation = new Simulation(0, aiPlayers, randomPlayers, ConnectionAI, rules, id, -1);

        while (!simulation.isGameOver()) {
            simulation.playTurn();
        }
    }

    private static void displayRules(TrainingPhase phase) {
        System.out.println("Rules: "+
                "Stacking: " + phase.ruleSpecs[0] + ", " +
                "Skip N' Flip: " + phase.ruleSpecs[1] + ", " +
                "Seven Zero: " + phase.ruleSpecs[2] + ", " +
                "Force Play Drawn: " + phase.ruleSpecs[3] + ", " +
                "Draw and Play: " + phase.ruleSpecs[4] + ", " +
                "Draw to Match: " + phase.ruleSpecs[5] + ", " +
                "Bluffing: " + phase.ruleSpecs[6] + ", " +
                "Play Identical: " + phase.ruleSpecs[7]
        );
    }
}

package uno.ai.training;

import uno.ai.network.ConnectionAI;
import uno.game.engine.Simulation;

import java.io.IOException;
import java.util.List;
import java.util.Random;

public class Training {

    private static final String DEFAULT_CONFIG = "res/training_official_4p_100.properties";

    public static void main(String[] args) {
        String configPath = args.length > 0 ? args[0] : DEFAULT_CONFIG;

        TrainingConfig config;
        try {
            config = TrainingConfig.load(configPath);
        } catch (IOException e) {
            System.err.println("Failed to load config from '" + configPath + "': " + e.getMessage());
            System.exit(1);
            return;
        }

        System.out.println("Loaded config: " + config);
        System.out.println("From: " + configPath);

        for (int i = 0; i < config.numClients; i++) {
            int port = config.startPort + i;
            String id = String.valueOf(i + 1);
            new Thread(() -> runRoutine(port, id, config), "trainer-" + id).start();
        }
    }

    private static void runRoutine(int port, String id, TrainingConfig config) {
        ConnectionAI ConnectionAI = new ConnectionAI();

        try {
            ConnectionAI.connect(port);
        } catch (IOException e) {
            throw new RuntimeException("Thread " + id + " could not connect on port " + port, e);
        }

        List<TrainingPhase> phases = config.phases;
        int loopStart = config.loopStartPhase - 1;

        for (int i = 0; i < loopStart; i++) {
            runPhase(phases.get(i), id, ConnectionAI);
            printCycleComplete(id, i + 1, phases.get(i));
        }

        if (config.loopInfinite) {
            while (true) {
                try {
                    for (int i = loopStart; i < phases.size(); i++) {
                        runPhase(phases.get(i), id, ConnectionAI);
                        printCycleComplete(id, i + 1, phases.get(i));
                    }
                } catch (Exception e) {
                    System.err.println(id + ". Unhandled exception in training loop.");
                    throw new RuntimeException(e);
                }
            }
        } else {
            for (int i = loopStart; i < phases.size(); i++) {
                runPhase(phases.get(i), id, ConnectionAI);
                printCycleComplete(id, i + 1, phases.get(i));
            }
        }
    }

    private static void runPhase(TrainingPhase phase, String id, ConnectionAI ConnectionAI) {
        switch (phase.type) {
            case FIXED: runFixedPhase (phase, id, ConnectionAI); break;
            case RANDOM_AI: runRandomAIPhase (phase, id, ConnectionAI); break;
            case MIXED: runMixedPhase (phase, id, ConnectionAI); break;
            case EXHAUSTIVE: runExhaustivePhase(phase, id, ConnectionAI); break;
        }
    }

    private static void runFixedPhase(TrainingPhase phase, String id, ConnectionAI ConnectionAI) {
        Random rng = new Random();
        System.out.println(id + ". [FIXED] " + phase.games + " games - " + phase.aiPlayers + " AI, " + phase.randomPlayers + " random players.");
        displayRules(phase);

        for (int i = 0; i < phase.games; i++) {
            runGame(phase.aiPlayers, phase.randomPlayers, phase.resolveRules(rng), id, ConnectionAI);
        }
    }

    private static void runRandomAIPhase(TrainingPhase phase, String id, ConnectionAI ConnectionAI) {
        Random rng = new Random();
        int range = phase.aiPlayersMax - phase.aiPlayersMin + 1;
        System.out.println(id + ". [RANDOM_AI] " + phase.games + " games - minimum of " + phase.aiPlayersMin + " AI players and maximum of " + phase.aiPlayersMax + " AI players.");
        displayRules(phase);

        for (int i = 0; i < phase.games; i++) {
            int aiPlayers = rng.nextInt(range) + phase.aiPlayersMin;
            runGame(aiPlayers, 0, phase.resolveRules(rng), id, ConnectionAI);
        }
    }

    private static void runMixedPhase(TrainingPhase phase, String id, ConnectionAI ConnectionAI) {
        Random rng = new Random();
        int range = phase.aiPlayersMax - phase.aiPlayersMin + 1;
        System.out.println(id + ". [MIXED] " + phase.games + " games - minimum of " + phase.aiPlayersMin + " AI players and maximum of " + phase.aiPlayersMax + " AI players.");
        displayRules(phase);

        for (int i = 0; i < phase.games; i++) {
            int aiPlayers = rng.nextInt(range) + phase.aiPlayersMin;
            int maxRandom = 10 - aiPlayers;
            int randomPlayers = maxRandom == 0 ? 1 : rng.nextInt(maxRandom) + 1;
            runGame(aiPlayers, randomPlayers, phase.resolveRules(rng), id, ConnectionAI);
        }
    }

    private static void runExhaustivePhase(TrainingPhase phase, String id, ConnectionAI ConnectionAI) {
        Random rng = new Random();
        System.out.println(id + ". [EXHAUSTIVE] " + phase.iterations + " iterations.");
        displayRules(phase);

        for (int k = 0; k < phase.iterations; k++) {
            for (int total = 2; total <= 10; total++) {
                for (int ai = 1; ai < total; ai++) {
                    runGame(ai, total - ai, phase.resolveRules(rng), id, ConnectionAI);
                }
                System.out.println(id + ". All possible games with " + total + " players done.");
            }
        }
    }

    private static void runGame(int aiPlayers, int randomPlayers, boolean[] rules, String id, ConnectionAI ConnectionAI) {
        Simulation simulation = new Simulation(0, aiPlayers, randomPlayers, ConnectionAI, rules, id, -1);

        while (!simulation.isGameOver()) {
            simulation.playTurn();
        }
    }

    private static void displayRules(TrainingPhase phase) {
        System.out.println("Rules: "+
                "Stacking: " + phase.ruleSpecs[0] + ", " +
                "Skip N' Flip: " + phase.ruleSpecs[1] + ", " +
                "Seven Zero: " + phase.ruleSpecs[2] + ", " +
                "Force Play Drawn: " + phase.ruleSpecs[3] + ", " +
                "Draw and Play: " + phase.ruleSpecs[4] + ", " +
                "Draw to Match: " + phase.ruleSpecs[5] + ", " +
                "Bluffing: " + phase.ruleSpecs[6] + ", " +
                "Play Identical: " + phase.ruleSpecs[7]
        );
    }

    private static void printCycleComplete(String id, int phaseIndex, TrainingPhase phase) {
        String label = phase != null && phase.type != null ? phase.type.name() : "UNKNOWN";
        System.out.println(id + ". Training cycle completed (phase " + phaseIndex + ", " + label + ").");
    }
}
